import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithPathAndCharset() throws IOException {
        Path path = mock(Path.class);
        BufferedWriter writer = mock(BufferedWriter.class);
        CSVPrinter printer = mock(CSVPrinter.class);

        try (MockedStatic<Files> filesMockedStatic = org.mockito.Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(path, StandardCharsets.UTF_8)).thenReturn(writer);
            CSVFormat spyFormat = spy(csvFormat);
            doReturn(printer).when(spyFormat).print(writer);

            CSVPrinter result = spyFormat.print(path, StandardCharsets.UTF_8);
            assertNotNull(result);
            assertEquals(printer, result);

            filesMockedStatic.verify(() -> Files.newBufferedWriter(path, StandardCharsets.UTF_8));
            verify(spyFormat).print(writer);
        }
    }

    @Test
    void testPrintWithIOExceptionFromFilesNewBufferedWriter() throws IOException {
        Path path = mock(Path.class);

        try (MockedStatic<Files> filesMockedStatic = org.mockito.Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(path, StandardCharsets.UTF_8))
                    .thenThrow(new IOException("Test IOException"));

            IOException thrown = assertThrows(IOException.class, () -> csvFormat.print(path, StandardCharsets.UTF_8));
            assertEquals("Test IOException", thrown.getMessage());
        }
    }
}
